INSERT INTO `mybb_sg_sg_virtudes` (`virtud_id`, `nombre`, `puntos`, `exclusivo`, `descripcion`) VALUES
('VAFIEL', 'Afinidad Elemental', 4, 0, 'La afinidad elemental del ninja es tanta que es capaz de elegir su elemento inicial entre los que tenga disponibles. (No se hace tirada aleatoria de elemento).'),
('VTENEL', 'Tendencia Elemental', 2, 0, 'El ninja tiene cierta tendencia elemental hacia ciertos elementos. Se establece un rango de 2 o 3 elementos entre los que tenga disponibles y la tirada aleatoria será exclusivamente entre los elementos de la tendencia. Tras completar la tendencia, la tirada aleatoria para obtener un nuevo elemento se hará de manera normal.'),
('VCURAN', 'Curandero', 3, 0, 'El ninja tiene conocimientos básicos sobre el tratamiento de heridas y remedios. Es útil en situaciones de emergencia pero jamás sustituirá a un verdadero Ninja Médico. Esta habilidad le ayudará a emplear las habilidades curativas del árbol Yang en otros ninjas.'),
('VHIBRI', 'Clan Híbrido', 5, 0, 'El ninja nació de la unión de dos padres de clanes diferentes, heredando las habilidades de ambos linajes. (Ambos clanes deben ser de la misma aldea). De escoger dos clanes con dōjutsu, se tendrá uno de cada uno. De escoger un clan con dōjutsu, solo se podrá usar la técnica de un ojo. El personaje tiene acceso únicamente a tres ramas entre todas las ramas de sus dos clanes. El límite de tres especialidades se mantiene entre todas las especialidades de sus dos clanes.'),
('VBFLUJ', 'Buen Flujo', 3, 0, 'El flujo de chakra del ninja es fluido, provocando un menor desgaste al usar chakra. (Incompatible con Mal Flujo).\n\n-10% de coste de chakra a todas las técnicas.'),
('VCARIS', 'Presencia Carismática', 1, 0, 'El ninja tiene una forma natural de expresarse y comportarse que genera simpatía o respeto en los demás. Su actitud, tono de voz y lenguaje corporal facilitan que otras personas lo escuchen con atención y respondan de manera positiva. No siempre obtiene lo que quiere, pero suele empezar las interacciones con una ventaja social clara.'),
('VAMBES', 'Amigo de las Bestias', 1, 0, 'El ninja tiene facilidad para interactuar con animales, interpretando su comportamiento y manteniendo la calma en su presencia. Los animales suelen responder mejor a sus órdenes o acercarse con menos resistencia. Esta habilidad no garantiza obediencia total, pero reduce reacciones agresivas.'),
('VATRAC', 'Atractivo', 1, 0, 'El ninja posee una belleza que no pasa desapercibida. Es posible que su presencia abra puertas invisibles o genere confianza donde no la había y convierte encuentros ordinarios en oportunidades inesperadas. (Incompatible con Feúra).'),
('VPROD1', 'Ninja Prodigio I', 3, 0, 'El usuario es capaz de aprender una especialidad más de cualquier árbol de habilidad que posea, rompiendo así el límite de tres especialidades por árbol de habilidad. (Solo una vez). (Incompatible con Ninja Prodigio II).'),
('VPROD2', 'Ninja Prodigio II', 5, 0, 'El ninja es tan hábil con la creación de técnicas y estilos que tiene acceso a un sexto árbol de habilidad, rompiendo el límite de cinco. El árbol obtenido por esta virtud se desbloquea al obtener todos los árboles según la guía. (Incompatible con Ninja Prodigio I).'),
('VFAMA', 'Fama', 2, 0, 'El ninja mantiene un aumento del 10% en su Bingo. (Incompatible con Impopularidad).'),
('VADIN1', 'Adinerado I', 1, 0, 'El ninja empieza con 1000 Ryos y además todos los objetos que compre costarán un 5% menos. (Incompatible con Adinerado II y III. Incompatible con Comprador Impulsivo I, II y III).'),
('VADIN2', 'Adinerado II', 2, 0, 'El ninja empieza con 2000 Ryos y además todos los objetos que compre costarán un 10% menos. (Incompatible con Adinerado I y III. Incompatible con Comprador Impulsivo I, II y III).'),
('VADIN3', 'Adinerado III', 3, 0, 'El ninja empieza con 3000 Ryos y además todos los objetos que compre costarán un 15% menos. (Incompatible con Adinerado II y III. Incompatible con Comprador Impulsivo I, II y III).'),
('VINTIM', 'Presencia Intimidante', 1, 0, 'La sola presencia del ninja basta para tensar el ambiente. Hay algo en su porte, en su mirada o en la forma en que ocupa el espacio, que impone silencio y siembra cautela en quienes le rodean.'),
('VINSUP', 'Instinto de Supervivencia', 4, 0, 'Los sentidos del ninja se avivan cuando este está cerca de la muerte, buscando sobrevivir. Cuando los PV del ninja estén por debajo del 20% total, todos sus atributos aumentarán en 10 puntos y solo podrá ejecutar acciones defensivas o evasivas. (Incompatible con Voluntad Vacilante).'),
('VLIDER', 'Líder Nato', 1, 0, 'El ninja tiene facilidad para dirigir y mandar a otras personas, haciendo que estos últimos lo vean como un líder capaz. No se garantiza que suceda siempre, pero facilita la obediencia de los que rodean al ninja.'),
('VBRUJU', 'Brújula Interna', 1, 0, 'El ninja tiene un sentido de orientación confiable que le permite recordar rutas y ubicaciones con facilidad. Incluso en lugares desconocidos, suele encontrar el camino correcto sin depender constantemente de ayuda externa.'),
('VNADAD', 'Nadador de Corriente', 2, 0, 'El ninja se desplaza por el agua con una gran técnica y facilidad. (No compatible con Hoshigaki).\n\n[MFUEx1] de Velocidad'),
('VPRACT', 'Primer Acto', 3, 0, 'El ninja empezará con 100 puntos de Bingo.'),
('VCONT1', 'Contactos I', 2, 0, 'El ninja tiene contacto con algún NPC de baja importancia en la historia. Máximo nivel 5. (Se pacta con el equipo de Narradores).\n\nAlgún NPC dentro de la historia tiene contacto con el personaje. Incompatible con Contactos II.'),
('VCONT2', 'Contactos II', 4, 0, 'El ninja tiene contacto con algún NPC importante en la historia. Máximo nivel 15. (Se pacta con el equipo de Narradores).\n\nAlgún NPC dentro de la historia tiene contacto con el personaje. Incompatible con Contactos I.'),
('VPINF1', 'Pasado Influyente I', 1, 0, 'El ninja nació en el seno de una familia de renombre, ya sea dentro o fuera de un clan, su nombre resuena con prestigio incluso antes de presentarse. Este legado le otorga una ventaja sutil pero constante, facilitando vínculos, generando confianza inicial y abriendo oportunidades que para otros permanecerían cerradas. (Incompatible con Pasado Oscuro I y II y Pasado Influyente II).\n\nCreación de un NPC propio de máximo nivel 10 y rango Chunin que sea familiar del personaje.'),
('VPINF2', 'Pasado Influyente II', 3, 0, 'El ninja nació en el seno de una familia de renombre, ya sea dentro o fuera de un clan, su nombre resuena con prestigio incluso antes de presentarse. Este legado le otorga una ventaja sutil pero constante, facilitando vínculos, generando confianza inicial y abriendo oportunidades que para otros permanecerían cerradas. (Incompatible con Pasado Oscuro I y II y Pasado Influyente I).\n\nCreación de un NPC propio de máximo nivel 15 y rango Anbu o Tokubetsu Jōnin que sea familiar del personaje.'),
('VFERRE', 'Voluntad Férrea', 1, 0, 'Las amenazas, la presión o los intentos de intimidación pierden efecto en el ninja. Su mente se mantiene firme incluso en situaciones hostiles, resistiendo al miedo con determinación inamovible.'),
('VMENTI', 'Mentira Convincente', 2, 0, 'El ninja tiene facilidad para inventar historias creíbles y mantener la coherencia cuando oculta información o engaña a otros. Sabe improvisar respuestas rápidas y controlar sus expresiones para no delatarse fácilmente. Esta habilidad no lo hace infalible, pero aumenta sus posibilidades de sostener una mentira bajo presión.'),
('VPULMO', 'Pulmón de Buceador', 2, 0, 'Tiene una capacidad respiratoria desarrollada que le permite contener la respiración durante más tiempo que otras personas. Puede mantener el control del aire incluso bajo esfuerzo físico o en situaciones exigentes.\n\nAguantar la respiración por 3 turnos más.'),
('VRDIF1', 'Rasgo Diferente I', 1, 0, 'El ninja posee un rasgo físico diferente al de todos, algo inusual como piel de otro color, cuernos, un tercer ojo, etcétera. Esto es meramente estético y no tiene funciones bélicas.'),
('VRDIF2', 'Rasgo Diferente II', 3, 0, 'El ninja posee un rasgo físico diferente al de todos, algo inusual como piel de otro color, cuernos, un tercer ojo, etcétera. Esta diferencia puede tener capacidades bélicas muy básicas.\n\nEl usuario puede crear una pasiva bélica gratuita de su rasgo físico diferente, la cual, será evaluada por el staff.'),
('VAPREN', 'Buen Aprendiz', 4, 0, 'El ninja es capaz de memorizar el funcionamiento de sus técnicas con más facilidad y tiene buena imaginación para la creación de ellas. El coste de Tobis para crear técnicas únicas en solitario se reduce en un -10%.'),
('VBORGA', 'Bien Organizado', 2, 0, 'El ninja sabe organizar sus objetos para tener la mayor optimización en su inventario.\n\nSe pueden llevar en el inventario un objeto más de todos los objetos excepto espadas.'),
('VROSTR', 'Rostro Común', 1, 0, 'El ninja tiene facilidad para pasar desapercibido, siempre y cuando no se encuentre en lugares extraños o en donde no debería estar.'),
('VINVES', 'Investigador', 4, 0, 'El ninja tiene un talento nato para la investigación. Lo que le ayuda a enterarse antes de las cosas.\n\nAl inicio de una misión o evento, el usuario recibe información sobre la trama, pudiendo ser para objetivos principales como secundarios de esta.'),
('VHEREN', 'Herencia Familiar', 2, 0, 'La familia del ninja ha mantenido un objeto por generaciones y ha llegado el momento de que el ninja mismo lo herede.\n\nSe podrá elegir gratis cualquier objeto de la tienda. Solo uno.'),
('VSENS1', 'Capacidad Sensorial Aumentada I', 2, 0, 'El ninja tiene uno de sus sentidos (oído, olfato, tacto, vista, gusto) bastante desarrollado a elección. Dándole ciertas ventajas al momento de usar ese sentido. (No podrá cambiar el sentido en el transcurso de la historia). Incompatible con Capacidad Sensorial Aumentada II.\n\nOído: Una vez por combate podrá anular el sigilo en un ataque.\nOlfato: Una vez por tema podrá usar su nariz para escanear olores de personas que haya asociado con anterioridad.\nTacto: Una vez por combate, reduce en -20% el daño de algún ataque siempre y cuando haga el bloqueo con sus manos.\nVista: Una vez por combate podrá esquivar como si los jutsus enemigos tuvieran -1 nivel siempre y cuando pueda verlo.\nGusto: Una vez por tema, al probar una sustancia o comida, podrá identificar si contiene venenos, toxinas o componentes extraños.'),
('VSENS2', 'Capacidad Sensorial Aumentada II', 5, 0, 'El ninja tiene dos de sus sentidos (oído, olfato, tacto, vista, gusto) bastante desarrollado a elección. Dándole ciertas ventajas al momento de usar esos sentidos. (No podrá cambiar los sentidos en el transcurso de la historia). Incompatible con Capacidad Sensorial Aumentada I.\n\nOído: Una vez por combate podrá anular el sigilo en un ataque.\nOlfato: Una vez por tema podrá usar su nariz para escanear olores de personas que haya asociado con anterioridad.\nTacto: Una vez por combate, reduce en -20% el daño de algún ataque siempre y cuando haga el bloqueo con sus manos.\nVista: Una vez por combate podrá esquivar como si los jutsus enemigos tuvieran -1 nivel siempre y cuando pueda verlo.\nGusto: Una vez por tema, al probar una sustancia o comida, podrá identificar si contiene venenos, toxinas o componentes extraños.'),
('VMEDIU', 'Médium', 4, 0, 'El ninja es capaz de servir como un puente entre vivos y muertos. Una vez por tema podrá intentar contactar con el espíritu de alguien fallecido (sabiendo de antemano que alguien murió ahí) para obtener información limitada a discreción del narrador. En temas sociales, se podrá usar las veces que se quieran pero no se puede obtener información importante o de peso para la trama global.'),
('VSANRE', 'Sangre Resistente', 2, 0, 'Todos los sangrados del ninja se reducen en un nivel de intensidad. (Incompatible con Sangre Diluida).'),
('VASCET', 'Disciplina Ascética', 2, 0, 'El ninja se ha acostumbrado a soportar condiciones adversas, su cuerpo puede resistir largos periodos sin alimento ni bebida. Gracias a un entrenamiento riguroso o una constitución excepcional, es capaz de mantenerse funcional durante varios días aun cuando los recursos escasean.\n\nEl ninja es capaz de resistir hasta tres días sin comer alimentos o ingerir bebidas. (Aplicable en eventos, tramas y misiones de larga duración on-rol).');
